let values = msg.payload;
let status = [];
let names = env.get("scale_names") || []; // Ensure names is at least an empty array
let current = global.get("scale_readings") || []; // Ensure current is at least an empty array
let start = global.get("shift_readings") || {}; // Ensure start is at least an empty object

for (let i = 0; i < values.length; i++) {
    let shift = 0;

    if (current.length === 0 || !start.hasOwnProperty('Scale' + (i + 1))) {
        shift = 0; // If current is empty or start does not contain the scale, set shift to 0
    } else {
        if (current[i] && typeof current[i].total !== "undefined") {
            shift = current[i].total - (start['Scale' + (i + 1)] || 0); // Use 0 if start['ScaleX'] is undefined
        } else {
            shift = 0;
        }
    }

    let obj = values[i];

    // Ensure valid datetime parsing
    let timeVal = obj.time_val ? new Date(obj.time_val) : new Date();
    let timeNow = obj.time_now ? new Date(obj.time_now) : new Date();

    let title = names[i] || ""; // If names[i] is undefined, use an empty string

    // Calculate the difference in minutes
    let diffMilliseconds = Math.abs(timeNow.getTime() - timeVal.getTime());
    let diffMinutes = diffMilliseconds / (1000 * 60);

    // Check if the difference is within five minutes
    let isMoreThanFiveMinutes = diffMinutes <= 5;

    let B = {
        id: obj.id,
        title: title,
        datetime: obj.time_val,
        status: isMoreThanFiveMinutes,
        time: diffMinutes,
        total: obj.total,
        hopper: obj.hopper,
        coms: obj.coms === 1,
        rate: obj.rate,
        shift: shift
    };

    status.push(B);
}

msg.payload = status;
return msg;

